    {
      "evidence_id": "evidence_001",
      "lecture_id": "calculus_gradient_challenge_001",
      "span": "The gradient of a differentiable scalar function is the vector of its partial derivatives. In coordinates, the gradient formula is"
    },
    {
      "evidence_id": "evidence_002",
      "lecture_id": "calculus_gradient_challenge_001",
      "span": "\\[\n\\nabla f(x) = \\left(\\frac{\\partial f}{\\partial x_1},\\ldots,\\frac{\\partial f}{\\partial x_d}\\right).\n\\]"
    },
    {
      "evidence_id": "evidence_003",
      "lecture_id": "calculus_gradient_challenge_001",
      "span": "The gradient is a mathematical concept, while the coordinate expression is a Formula that formalizes it."
    },
    {
      "evidence_id": "evidence_004",
      "lecture_id": "optimisation_gradient_challenge_001",
      "span": "The gradient vector points in the direction of steepest local increase of a differentiable objective. Gradient descent is an iterative Method that moves in the opposite direction of this gradient vector to reduce the objective."
    }
  ]
